import { useState } from "react";
import "./style.css";

function App() {
  const imageData = [
    {
      id: 1,
      title: "Julie's Rabbit Ears",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1517849845537-4d257902454a?w=400"
    },

    {
      id: 2,
      title: "The Innocent Look",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=400"
    },

    {
      id: 3,
      title: "Big Eyed Buggy",
      category: "Pug",
      url: "https://images.unsplash.com/photo-1518020382113-a7e8fc38eac9?w=400"
    },

    {
      id: 4,
      title: "The Saint Doggo",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1517423440428-a5a00ad493e8?w=400"
    },

    {
      id: 5,
      title: "Big Eyed Buggy",
      category: "Pug",
      url: "https://images.unsplash.com/photo-1518020382113-a7e8fc38eac9?w=400"
    },

    {
      id: 6,
      title: "The Innocent Look",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=400"
    },

    {
      id: 7,
      title: "The Saint Doggo",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1517423440428-a5a00ad493e8?w=400"
    },

    {
      id: 8,
      title: "Julie's Rabbit Ears",
      category: "Dog",
      url: "https://images.unsplash.com/photo-1517849845537-4d257902454a?w=400"
    }
  ];

  const [search, setSearch] = useState("");
  const [darkMode, setDarkMode] = useState(false);

  const filteredImages = imageData.filter((item) =>
    item.title.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className={darkMode ? "dark container" : "container"}>
      <div className="top-section">
        <h1 className="title">Dynamic Image Gallery</h1>

        <button
          className="dark-btn"
          onClick={() => setDarkMode(!darkMode)}
        >
          {darkMode ? "Light Mode" : "Dark Mode"}
        </button>
      </div>

      <input
        type="text"
        placeholder="Search images..."
        className="search"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <p className="count">
        Total Images: {filteredImages.length}
      </p>

      <div className="gallery">
        {filteredImages.map((item) => (
          <div className="card" key={item.id}>
            <img src={item.url} alt={item.title} />

            <div className="card-content">
              <h3>{item.title}</h3>

              <p>{item.category}</p>

              <button className="download-btn">
                Download
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
